rules:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper functions
    function isAuthenticated() {
      return request.auth != null;
    }

    function isOwner(userId) {
      return request.auth.uid == userId;
    }

    function isAdmin() {
      return request.auth.token.role == 'admin';
    }

    // Users Collection
    match /users/{userId} {
      allow read: if isAuthenticated();
      allow write: if isOwner(userId) || isAdmin();

      // Nested settings collections
      match /settings/{docId} {
        allow read, write: if isOwner(userId);
      }
    }

    // Carbon footprint logging collections
    match /activities/{docId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAuthenticated() && resource.data.userId == request.auth.uid;
    }

    match /carbonHistory/{docId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow write: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
    }

    match /travel/{docId} {
      allow read, write: if isAuthenticated() && (resource.data.userId == request.auth.uid || request.resource.data.userId == request.auth.uid);
    }

    match /meals/{docId} {
      allow read, write: if isAuthenticated() && (resource.data.userId == request.auth.uid || request.resource.data.userId == request.auth.uid);
    }

    match /receipts/{docId} {
      allow read, write: if isAuthenticated() && (resource.data.userId == request.auth.uid || request.resource.data.userId == request.auth.uid);
    }

    match /energy/{docId} {
      allow read, write: if isAuthenticated() && (resource.data.userId == request.auth.uid || request.resource.data.userId == request.auth.uid);
    }

    // Challenges & Gamification
    match /challenges/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    match /rewards/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    match /wallet/{docId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow write: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
    }

    match /achievements/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    match /reports/{docId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow write: if isAdmin();
    }

    match /notifications/{docId} {
      allow read: if isAuthenticated() && resource.data.userId == request.auth.uid;
      allow write: if isAdmin() || (isAuthenticated() && request.resource.data.userId == request.auth.uid);
    }

    match /leaderboard/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    // Groups & Communities
    match /community/{docId} {
      allow read: if isAuthenticated();
      allow create: if isAuthenticated();
      allow update, delete: if isAuthenticated() && (resource.data.creatorId == request.auth.uid || isAdmin());
    }

    match /families/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAuthenticated();
    }

    match /colleges/{docId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    match /analytics/{docId} {
      allow read, write: if isAdmin();
    }
  }
}
